PRAGMA foreign_keys = ON;
CREATE TABLE IF NOT EXISTS roles (id INTEGER PRIMARY KEY, name TEXT UNIQUE, created_at TEXT DEFAULT CURRENT_TIMESTAMP, updated_at TEXT DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE IF NOT EXISTS permissions (id INTEGER PRIMARY KEY, module TEXT, page TEXT, action TEXT, created_at TEXT DEFAULT CURRENT_TIMESTAMP, updated_at TEXT DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE IF NOT EXISTS role_permissions (id INTEGER PRIMARY KEY, role_id INTEGER, permission_id INTEGER, created_at TEXT DEFAULT CURRENT_TIMESTAMP, updated_at TEXT DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE IF NOT EXISTS users (id INTEGER PRIMARY KEY, name TEXT, email TEXT UNIQUE, password TEXT, role_id INTEGER, department TEXT, job_title TEXT, active INTEGER DEFAULT 1, last_login TEXT, created_by INTEGER, updated_by INTEGER, deleted_at TEXT, created_at TEXT DEFAULT CURRENT_TIMESTAMP, updated_at TEXT DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE IF NOT EXISTS settings (id INTEGER PRIMARY KEY, key TEXT UNIQUE, value TEXT, created_at TEXT DEFAULT CURRENT_TIMESTAMP, updated_at TEXT DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE IF NOT EXISTS company (id INTEGER PRIMARY KEY, name TEXT, nif TEXT, address TEXT, email TEXT, phone TEXT, site TEXT, logo_path TEXT, primary_color TEXT, labor_rate REAL, bank_data TEXT, signature TEXT, pdf_footer TEXT, created_at TEXT DEFAULT CURRENT_TIMESTAMP, updated_at TEXT DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE IF NOT EXISTS company_contacts (id INTEGER PRIMARY KEY, company_id INTEGER, name TEXT, email TEXT, phone TEXT, role TEXT, created_at TEXT DEFAULT CURRENT_TIMESTAMP, updated_at TEXT DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE IF NOT EXISTS departments (id INTEGER PRIMARY KEY, name TEXT, manager TEXT, description TEXT, deleted_at TEXT, created_at TEXT DEFAULT CURRENT_TIMESTAMP, updated_at TEXT DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE IF NOT EXISTS job_roles (id INTEGER PRIMARY KEY, department_id INTEGER, name TEXT, description TEXT, responsibilities TEXT, competencies TEXT, deleted_at TEXT, created_at TEXT DEFAULT CURRENT_TIMESTAMP, updated_at TEXT DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE IF NOT EXISTS employees (id INTEGER PRIMARY KEY, name TEXT, email TEXT, phone TEXT, address TEXT, birth_date TEXT, employee_number TEXT, department_id INTEGER, job_role_id INTEGER, manager_id INTEGER, hire_date TEXT, exit_date TEXT, status TEXT, contract_type TEXT, notes TEXT, emergency_contact TEXT, internal_number TEXT, skills TEXT, training TEXT, deleted_at TEXT, created_at TEXT DEFAULT CURRENT_TIMESTAMP, updated_at TEXT DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE IF NOT EXISTS clients (id INTEGER PRIMARY KEY, name TEXT,nif TEXT,address TEXT,email TEXT,phone TEXT,website TEXT,contact_name TEXT,contact_email TEXT,commercial_terms TEXT,notes TEXT,doc_template TEXT,status TEXT,deleted_at TEXT,created_at TEXT DEFAULT CURRENT_TIMESTAMP,updated_at TEXT DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE IF NOT EXISTS client_contacts (id INTEGER PRIMARY KEY, client_id INTEGER, name TEXT, role TEXT, email TEXT, phone TEXT, notes TEXT, created_at TEXT DEFAULT CURRENT_TIMESTAMP, updated_at TEXT DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE IF NOT EXISTS supplier_contacts (id INTEGER PRIMARY KEY, supplier_id INTEGER, name TEXT, role TEXT, email TEXT, phone TEXT, notes TEXT, created_at TEXT DEFAULT CURRENT_TIMESTAMP, updated_at TEXT DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE IF NOT EXISTS suppliers (id INTEGER PRIMARY KEY, name TEXT,nif TEXT,address TEXT,contact TEXT,email TEXT,phone TEXT,category TEXT,notes TEXT,status TEXT,deleted_at TEXT,created_at TEXT DEFAULT CURRENT_TIMESTAMP,updated_at TEXT DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE IF NOT EXISTS document_templates (id INTEGER PRIMARY KEY, type TEXT,name TEXT,content TEXT,deleted_at TEXT,created_at TEXT DEFAULT CURRENT_TIMESTAMP,updated_at TEXT DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE IF NOT EXISTS spec_books (id INTEGER PRIMARY KEY, code TEXT,title TEXT,client_id INTEGER,project TEXT,item_id INTEGER,version TEXT,status TEXT,responsible_id INTEGER,approval_date TEXT,objective TEXT,technical_requirements TEXT,quality_requirements TEXT,packaging_requirements TEXT,logistics_requirements TEXT,materials TEXT,tolerances TEXT,acceptance_criteria TEXT,notes TEXT,deleted_at TEXT,created_at TEXT DEFAULT CURRENT_TIMESTAMP,updated_at TEXT DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE IF NOT EXISTS spec_book_versions (id INTEGER PRIMARY KEY,spec_book_id INTEGER,version TEXT,change_log TEXT,created_at TEXT DEFAULT CURRENT_TIMESTAMP,updated_at TEXT DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE IF NOT EXISTS item_families (id INTEGER PRIMARY KEY, name TEXT, code TEXT, description TEXT, parent_id INTEGER, status TEXT, deleted_at TEXT, created_at TEXT DEFAULT CURRENT_TIMESTAMP, updated_at TEXT DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE IF NOT EXISTS items (id INTEGER PRIMARY KEY, code TEXT,description TEXT,client_id INTEGER,family_id INTEGER,subfamily TEXT,unit TEXT,prod_time REAL,qc_time REAL,raw_cost REAL,op_cost REAL,sale_price REAL,status TEXT,notes TEXT,deleted_at TEXT,created_at TEXT DEFAULT CURRENT_TIMESTAMP,updated_at TEXT DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE IF NOT EXISTS orders (id INTEGER PRIMARY KEY, order_no TEXT, client_id INTEGER, client_ref TEXT, order_date TEXT, delivery_date TEXT, status TEXT, notes TEXT, deleted_at TEXT, created_at TEXT DEFAULT CURRENT_TIMESTAMP, updated_at TEXT DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE IF NOT EXISTS order_lines (id INTEGER PRIMARY KEY, order_id INTEGER,item_id INTEGER,description TEXT,quantity REAL,unit_price REAL,discount REAL,total_value REAL,expected_cost REAL,expected_margin REAL,notes TEXT,created_at TEXT DEFAULT CURRENT_TIMESTAMP,updated_at TEXT DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE IF NOT EXISTS production_orders (id INTEGER PRIMARY KEY, of_no TEXT,order_id INTEGER,client_id INTEGER,item_id INTEGER,qty_planned REAL,qty_produced REAL,qty_ok REAL,qty_nok REAL,start_date TEXT,end_date TEXT,status TEXT,team TEXT,operator_id INTEGER,time_expected REAL,time_real REAL,cost_expected REAL,cost_real REAL,notes TEXT,deleted_at TEXT,created_at TEXT DEFAULT CURRENT_TIMESTAMP,updated_at TEXT DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE IF NOT EXISTS production_reports (id INTEGER PRIMARY KEY,report_date TEXT,employee_id INTEGER,team TEXT,production_order_id INTEGER,item_id INTEGER,qty_produced REAL,qty_ok REAL,qty_nok REAL,time_spent REAL,stops TEXT,stop_reason TEXT,notes TEXT,status TEXT,deleted_at TEXT,created_at TEXT DEFAULT CURRENT_TIMESTAMP,updated_at TEXT DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE IF NOT EXISTS warehouses (id INTEGER PRIMARY KEY,name TEXT,code TEXT,address TEXT,status TEXT,deleted_at TEXT,created_at TEXT DEFAULT CURRENT_TIMESTAMP,updated_at TEXT DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE IF NOT EXISTS warehouse_sections (id INTEGER PRIMARY KEY,warehouse_id INTEGER,name TEXT,code TEXT,created_at TEXT DEFAULT CURRENT_TIMESTAMP,updated_at TEXT DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE IF NOT EXISTS warehouse_locations (id INTEGER PRIMARY KEY,section_id INTEGER,code TEXT,description TEXT,capacity REAL,type TEXT,status TEXT,deleted_at TEXT,created_at TEXT DEFAULT CURRENT_TIMESTAMP,updated_at TEXT DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE IF NOT EXISTS stock_items (id INTEGER PRIMARY KEY,item_id INTEGER,description TEXT,quantity REAL,unit TEXT,location_id INTEGER,batch TEXT,entry_date TEXT,expiry_date TEXT,notes TEXT,created_at TEXT DEFAULT CURRENT_TIMESTAMP,updated_at TEXT DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE IF NOT EXISTS stock_movements (id INTEGER PRIMARY KEY,type TEXT,reference TEXT,item_id INTEGER,quantity REAL,origin_id INTEGER,destination_id INTEGER,partner TEXT,document_ref TEXT,status TEXT,user_id INTEGER,movement_date TEXT,notes TEXT,created_at TEXT DEFAULT CURRENT_TIMESTAMP,updated_at TEXT DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE IF NOT EXISTS planner_entries (id INTEGER PRIMARY KEY,week TEXT,production_order_id INTEGER,order_id INTEGER,client_id INTEGER,item_id INTEGER,quantity REAL,expected_time REAL,team TEXT,urgency TEXT,status TEXT,comments TEXT,created_at TEXT DEFAULT CURRENT_TIMESTAMP,updated_at TEXT DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE IF NOT EXISTS calendars (id INTEGER PRIMARY KEY,name TEXT,module TEXT,color TEXT,created_at TEXT DEFAULT CURRENT_TIMESTAMP,updated_at TEXT DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE IF NOT EXISTS calendar_events (id INTEGER PRIMARY KEY,calendar_id INTEGER,title TEXT,start_at TEXT,end_at TEXT,recurrence TEXT,participants TEXT,ref_type TEXT,ref_id INTEGER,reminder_minutes INTEGER,notes TEXT,created_at TEXT DEFAULT CURRENT_TIMESTAMP,updated_at TEXT DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE IF NOT EXISTS calendar_integrations (id INTEGER PRIMARY KEY,provider TEXT,token TEXT,refresh_token TEXT,status TEXT,last_sync TEXT,created_at TEXT DEFAULT CURRENT_TIMESTAMP,updated_at TEXT DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE IF NOT EXISTS audits (id INTEGER PRIMARY KEY,code TEXT,title TEXT,type TEXT,department_id INTEGER,responsible_id INTEGER,auditor_id INTEGER,planned_date TEXT,performed_date TEXT,status TEXT,checklist TEXT,score REAL,non_conformities TEXT,corrective_actions TEXT,due_date TEXT,evidence TEXT,notes TEXT,deleted_at TEXT,created_at TEXT DEFAULT CURRENT_TIMESTAMP,updated_at TEXT DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE IF NOT EXISTS audit_checklists (id INTEGER PRIMARY KEY,name TEXT,type TEXT,created_at TEXT DEFAULT CURRENT_TIMESTAMP,updated_at TEXT DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE IF NOT EXISTS audit_checklist_items (id INTEGER PRIMARY KEY,checklist_id INTEGER,item TEXT,weight REAL,created_at TEXT DEFAULT CURRENT_TIMESTAMP,updated_at TEXT DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE IF NOT EXISTS audit_findings (id INTEGER PRIMARY KEY,audit_id INTEGER,finding TEXT,severity TEXT,action TEXT,due_date TEXT,status TEXT,created_at TEXT DEFAULT CURRENT_TIMESTAMP,updated_at TEXT DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE IF NOT EXISTS tasks (id INTEGER PRIMARY KEY,title TEXT,description TEXT,type TEXT,priority TEXT,responsible_id INTEGER,department_id INTEGER,due_date TEXT,recurrence TEXT,status TEXT,notes TEXT,deleted_at TEXT,created_at TEXT DEFAULT CURRENT_TIMESTAMP,updated_at TEXT DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE IF NOT EXISTS task_schedules (id INTEGER PRIMARY KEY,task_id INTEGER,frequency TEXT,next_run TEXT,last_run TEXT,active INTEGER DEFAULT 1,created_at TEXT DEFAULT CURRENT_TIMESTAMP,updated_at TEXT DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE IF NOT EXISTS daily_reports (id INTEGER PRIMARY KEY,report_date TEXT,user_id INTEGER,department_id INTEGER,action TEXT,operation TEXT,result TEXT,notes TEXT,status TEXT,submitted_at TEXT,validated_by INTEGER,validated_at TEXT,created_at TEXT DEFAULT CURRENT_TIMESTAMP,updated_at TEXT DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE IF NOT EXISTS alerts (id INTEGER PRIMARY KEY,type TEXT,title TEXT,message TEXT,severity TEXT,module TEXT,reference_type TEXT,reference_id INTEGER,user_id INTEGER,status TEXT,created_at TEXT DEFAULT CURRENT_TIMESTAMP,updated_at TEXT DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE IF NOT EXISTS attachments (id INTEGER PRIMARY KEY,module TEXT,record_id INTEGER,file_path TEXT,file_name TEXT,mime_type TEXT,size INTEGER,created_at TEXT DEFAULT CURRENT_TIMESTAMP,updated_at TEXT DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE IF NOT EXISTS activity_logs (id INTEGER PRIMARY KEY,user_id INTEGER,module TEXT,action TEXT,record_id INTEGER,details TEXT,created_at TEXT DEFAULT CURRENT_TIMESTAMP,updated_at TEXT DEFAULT CURRENT_TIMESTAMP);
